session.start-client-session:
            ${client\-mac}
            <#if inner\-vlan\-pbit\-value?has_content>
              ${inner\-vlan\-pbit\-value}
            </#if>
            <#if outer\-vlan\-pbit\-value?has_content>
            ${outer\-vlan\-pbit\-value}
            </#if>
            <#if mru?has_content>
            ${mru}
            </#if>
            <#if authentication\-protocol?has_content && user\-name?has_content && password?has_content>
              ${authentication\-protocol}
	      ${user\-name}
              ${password}
            </#if>
            <#if time\-out?has_content>
            ${time\-out}
            </#if>
